--- 获取项目组多语言配置信息
local function Prepare()
    Localization.languageCode = {}
    for key, value in pairs(Localization.languageType) do
        Localization.languageCode[value] = key
    end

    local config = require("Config/LocaleConfigData")
    Localization.configData = config
end

local function GetSystemLanguage()
    local countryCode = CS.DH.NativeCore.Platform.DeviceUtility.GetLanguage()
    local languageCode = DefaultLanguage
    local splitCode = Split(countryCode,'_')

    --- 检查返回的语言格式是否正确，若不正确将使用默认的语言
    if #splitCode ~= 2 then
        return languageCode
    end

    --- 针对目前的多语言规则，特殊处理TW和其他简体中文的情况
    if countryCode == "zh_TW" then
        languageCode = "tw"
    elseif splitCode[1] == "zh" then
        languageCode = "cn"
    else
        languageCode = splitCode[1]
    end
    
    return languageCode
end

