--- 获取当前已选择的语言，若还未选择语言则获取系统语言
local function PrepareCurrentLanguage()
    local languageCode = GetLocalLanguage()
    if languageCode == nil then
        languageCode = GetSystemLanguage()
    end
    
    Localization.ChangeLanguage(languageCode,function()
        --- 语言切换完成
    end)
end

---@param code string @多语言文本ID：cn,en等
---@return LocaleConfigItem
local function GetLanguageConfig(code)
    local configData = Localization.configData
    local config = configData[code]
    --- 若不存在对于该语言的配置信息，则使用默认的配置信息
    if config == nil then
        return configData.default
    else
        return config
    end
end

local function NotifyOnLocalize()
    for _, v in pairs(Localization.onLocalize) do
        v.OnLocalize()
    end
end

--- 多语言切换接口，切换多语言为异步操作，需要等待多语言完成后进行其他操作
--- 多语言切换可能会触发资源更新逻辑
---@param code number | string @多语言数字ID：1,2,3或者多语言文本ID：cn,en等
---@param callback fun():void @多语言切换完成回调,仅适用于UI表现
function Localization.ChangeLanguage(code, callback)
    if Localization.configData == nil then
        error("需要先初始化多语言模块")
    end

    local languageKey = nil
    if type(code) == "number" then
        languageKey = Localization.languageCode[code]
    else
        languageKey = code
        if not Localization.languageType[code] then
            error("不支持的多语言Code" .. tostring(code))
        end
    end

    if not languageKey then
        error("不支持的多语言Code" .. tostring(code))
    end

    local config = GetLanguageConfig(languageKey)
    --- 配置信息一致，不需要对字体或者文本格式进行处理
    if config == Localization.currentConfig then
        NotifyOnLocalize()
        callback()
        return
    end

