--- 注册多语言切换回调
---@param target any @任意实现了OnLocalize函数的类型对象
function Localization.RegisterLocalize(target)
    if target.OnLocalize == nil then
        return
    end
    Localization.onLocalize[target] = target
end

--- 取消注册多语言切换回调
---@param target any @任意实现了OnLocalize函数的类型对象
function Localization.UnRegisterLocalize(target)
    Localization.onLocalize[target] = nil
end

